import csv
from collections import defaultdict

def title_county(name):
    return (name or '').strip().lower().title()

with open('datagov/texas-state-expenditures-by-county-2019/files/rows.txt', 'r', encoding='utf-8', newline='') as f:
    rows = list(csv.DictReader(f))

totals = defaultdict(float)
for r in rows:
    category = (r.get('Major Spending Category') or '').strip().upper()
    county = (r.get('County') or '').strip().upper()
    if category != 'CAPITAL OUTLAY' or not county:
        continue
    try:
        amount = float((r.get('Amount') or '').replace(',', '').strip())
    except (TypeError, ValueError):
        continue
    totals[county] += amount

ranked = sorted(totals.items(), key=lambda x: (-x[1], x[0]))[:5]
result = [title_county(county) for county, _ in ranked]

